<?php require_once '../../../includes/config.php'; require_once '../../../includes/db.php'; require_once '../../../includes/auth.php'; require_once '../../../includes/helpers.php'; require_role(['admin']); $pdo = get_pdo(); $page_title = 'Edit Dosen'; $current_page = 'dosen'; $nidn = isset($_GET['nidn']) ? trim($_GET['nidn']) : ''; if (!$nidn) { flash('error', 'NIDN tidak ditemukan'); redirect(APP_URL . '/admin/dosen/index.php'); exit; } $stmt = $pdo->prepare("SELECT * FROM dosen WHERE nidn = ?"); $stmt->execute([$nidn]); $dosen = $stmt->fetch(); if (!$dosen) { flash('error', 'Dosen tidak ditemukan'); redirect(APP_URL . '/admin/dosen/index.php'); exit; } $errors = []; $form_data = ['nama' => $dosen['nama'], 'email' => $dosen['email'], 'jurusan' => $dosen['jurusan']]; if ($_SERVER['REQUEST_METHOD'] === 'POST') { if (empty($_POST['_csrf']) || !csrf_verify($_POST['_csrf'])) { $errors[] = 'CSRF token tidak valid'; } $form_data['nama'] = trim($_POST['nama'] ?? ''); $form_data['email'] = trim($_POST['email'] ?? ''); $form_data['jurusan'] = trim($_POST['jurusan'] ?? ''); $password = $_POST['password'] ?? ''; if (empty($form_data['nama'])) { $errors[] = 'Nama harus diisi'; } if (empty($form_data['email']) || !is_valid_email($form_data['email'])) { $errors[] = 'Email tidak valid'; } if (empty($form_data['jurusan'])) { $errors[] = 'Jurusan harus diisi'; } if (!empty($password) && strlen($password) < 6) { $errors[] = 'Password minimal 6 karakter'; } if (empty($errors)) { try { if (!empty($password)) { $stmt = $pdo->prepare("UPDATE dosen SET nama = ?, email = ?, jurusan = ?, password = ? WHERE nidn = ?"); $stmt->execute([$form_data['nama'], $form_data['email'], $form_data['jurusan'], password_hash($password, PASSWORD_DEFAULT), $nidn]); } else { $stmt = $pdo->prepare("UPDATE dosen SET nama = ?, email = ?, jurusan = ? WHERE nidn = ?"); $stmt->execute([$form_data['nama'], $form_data['email'], $form_data['jurusan'], $nidn]); } flash('success', 'Dosen berhasil diperbarui'); redirect(APP_URL . '/admin/dosen/index.php'); exit; } catch (Exception $e) { $errors[] = 'Error: ' . $e->getMessage(); } } } ?> <!DOCTYPE html> <html lang="id"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title><?= h($page_title) ?> - SIAKAD Gallery</title> <link rel="stylesheet" href="<?= APP_URL ?>/assets/css/style.css"> <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.10.0/font/bootstrap-icons.css"> <style> .form-container { background: white; border-radius: 16px; padding: 32px; box-shadow: 0 2px 10px rgba(11, 30, 79, 0.06); max-width: 600px; } .form-group { margin-bottom: 20px; } .form-label { display: block; font-weight: 600; color: #0B1E4F; margin-bottom: 8px; font-size: 14px; } .form-control { width: 100%; padding: 10px 14px; border: 1px solid #E4E7EE; border-radius: 8px; font-size: 14px; font-family: inherit; } .form-control:focus { outline: none; border-color: #2A4A9E; background: #F0F4FF; } .form-control:disabled { background: #F5F6FA; color: #6B7489; cursor: not-allowed; } .form-actions { display: flex; gap: 12px; margin-top: 32px; padding-top: 24px; border-top: 1px solid #E4E7EE; } .btn-secondary { padding: 10px 20px; border-radius: 8px; border: 1px solid #E4E7EE; background: white; color: #2C3A59; text-decoration: none; cursor: pointer; font-weight: 500; } .alert-danger { background: #FFEBEE; border: 1px solid #EF9A9A; color: #C62828; padding: 12px 16px; border-radius: 8px; margin-bottom: 20px; } .form-hint { font-size: 12px; color: #6B7489; margin-top: 4px; } </style> </head> <body> <div class="app-container"> <?php include '../../../includes/header.php'; ?> <div class="main-content"> <?php include '../../../includes/sidebar.php'; ?> <div class="content-area"> <div style="margin-bottom: 24px;"> <h1><?= h($page_title) ?></h1> <p class="text-muted"><?= h($dosen['nama']) ?> (<?= h($dosen['nidn']) ?>)</p> </div> <div class="form-container"> <?php if (!empty($errors)): ?> <div class="alert-danger"> <ul style="margin: 0; padding-left: 20px;"> <?php foreach ($errors as $error): ?> <li><?= h($error) ?></li> <?php endforeach; ?> </ul> </div> <?php endif; ?> <form method="POST"> <input type="hidden" name="_csrf" value="<?= csrf_token() ?>"> <div class="form-group"> <label class="form-label">NIDN</label> <input type="text" class="form-control" value="<?= h($dosen['nidn']) ?>" disabled> <div class="form-hint">NIDN tidak dapat diubah</div> </div> <div class="form-group"> <label class="form-label">Nama Lengkap <span style="color: #E04F5F;">*</span></label> <input type="text" name="nama" class="form-control" value="<?= h($form_data['nama']) ?>" maxlength="100" required> </div> <div class="form-group"> <label class="form-label">Email <span style="color: #E04F5F;">*</span></label> <input type="email" name="email" class="form-control" value="<?= h($form_data['email']) ?>" maxlength="100" required> </div> <div class="form-group"> <label class="form-label">Jurusan <span style="color: #E04F5F;">*</span></label> <input type="text" name="jurusan" class="form-control" value="<?= h($form_data['jurusan']) ?>" maxlength="60" required> </div> <div class="form-group"> <label class="form-label">Password Baru</label> <input type="password" name="password" class="form-control" minlength="6"> <div class="form-hint">Biarkan kosong jika tidak ingin mengubah password</div> </div> <div class="form-actions"> <button type="submit" class="btn btn-primary"> <i class="bi bi-check-circle"></i> Simpan Perubahan </button> <a href="<?= APP_URL ?>/admin/dosen/index.php" class="btn-secondary"> <i class="bi bi-x-circle"></i> Batal </a> </div> </form> </div> </div> </div> </div> <?php include '../../../includes/footer.php'; ?> </body> </html>
